/** Assert committed native.ts was generated by export-native-ts. */
import { readFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const generated = join(root, "src/lib/generated/native.ts");
const header = "// @generated by export-native-ts — do not edit";

const text = readFileSync(generated, "utf8");
if (!text.startsWith(header)) {
	console.error(`missing generated header in ${generated}`);
	process.exit(1);
}
if (!text.includes("export type NativeSearchResponse")) {
	console.error(`NativeSearchResponse missing from ${generated}`);
	process.exit(1);
}
console.log("ok: generated native.ts present");
